/**
 * Converts milliseconds to days.
 * @param ms - The time in milliseconds.
 * @returns The time in days.
 */
export const msToDays = (ms: number): number => ms / (1000 * 60 * 60 * 24);

/**
 * Checks if a given date falls within the last N days from the current date.
 * @param date - The date to check.
 * @param days - The number of days to look back.
 * @returns True if the date is within the last N days, false otherwise.
 */
export const isDateWithinLastNDays = (date: Date, days: number): boolean => {
  const now = new Date();
  const nDaysAgo = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
  return date >= nDaysAgo && date <= now;
};
