```aether:src/velocityService.ts
import { mockTasks } from './data';
import { Task, VelocityReport } from './types';
import { isDateWithinLastNDays, msToDays } from './utils';

const VELOCITY_PERIOD_DAYS = 30;

/**
 * Calculates the team's task velocity metrics.
 * @param tasks - An array of tasks to analyze.
 * @returns A VelocityReport object containing tasks completed per day, average cycle time, and WIP count.
 */
export function calculateVelocity(tasks: Task[]): VelocityReport {
  const now = new Date();

  // 1. Filter completed tasks within the last N days
  const completedTasksInPeriod = tasks.filter(task =>
    task.status === 'done' &&
    task.completedAt &&
    isDateWithinLastNDays(task.completedAt, VELOCITY_PERIOD_DAYS)
  );

  // 2. Calculate Tasks Completed Per Day
  const tasksCompletedCount = completedTasksInPeriod.length;
  const tasksCompletedPerDay = tasksCompletedCount > 0
    ? tasksCompletedCount / VELOCITY_PERIOD_DAYS
    : 0;

  // 3. Calculate Average Cycle Time
  let totalCycleTimeMs = 0;
  if (tasksCompletedCount > 0) {
    for (const task of completedTasksInPeriod) {
      if (task.createdAt && task.completedAt) {
        totalCycleTimeMs += task.completedAt.getTime() - task.createdAt.getTime();
      }
    }
  }
  const averageCycleTimeInDays = tasksCompletedCount > 0
    ? msToDays(totalCycleTimeMs / tasksCompletedCount)
    : 0;

  // 4. Calculate Work In Progress (WIP) Count
  const workInProgressCount = tasks.filter(task => task.status === 'in-progress').length;

  return {
    periodInDays: VELOCITY_PERIOD_DAYS,
    tasksCompletedPerDay: parseFloat(tasksCompletedPerDay.toFixed(2)), // Round for readability
    averageCycleTimeInDays: parseFloat(averageCycleTimeInDays.toFixed(2)), // Round for readability
    workInProgressCount,
  };
}

/**
 * Fetches the velocity report using mock data.
 * In a real application, this would interact with a database or external API.
 */
export async function getVelocityReport(): Promise<VelocityReport> {
  // Simulate an async data fetch
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve(calculateVelocity(mockTasks));
    }, 50); // Small delay to simulate network latency
  });
}
